export function getBlogArticleEnBySlug(slug: string): BlogArticle | undefined {
  return BLOG_ARTICLES_EN.find(a => a.slug === slug);
}

export function getBlogArticlesEnByCategory(category: string): BlogArticle[] {
  return BLOG_ARTICLES_EN.filter(a => a.category === category);
}

export function getRelatedArticlesEn(slug: string, limit = 3): BlogArticle[] {
  const article = getBlogArticleEnBySlug(slug);
  if (!article) return [];
  return BLOG_ARTICLES_EN
    .filter(a => a.slug !== slug && a.category === article.category)
    .slice(0, limit);
}
